import{_ as p,c as e,o as i,ag as s}from"./chunks/framework.ELrfyV9R.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status":"pending","source":"web-clipper","url":"https://x.com/aehyok/status/2044239791231996394","created":"2026-04-15T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/Mac使用指南系列文章：从零搭建Codex App桌面端结合GitHub CLI，体验 AI 自动化克隆与提交.md","filePath":"ai/bookmark/Mac使用指南系列文章：从零搭建Codex App桌面端结合GitHub CLI，体验 AI 自动化克隆与提交.md","lastUpdated":1776945928000}'),t={name:"ai/bookmark/Mac使用指南系列文章：从零搭建Codex App桌面端结合GitHub CLI，体验 AI 自动化克隆与提交.md"};function o(l,a,n,r,m,h){return i(),e("div",null,a[0]||(a[0]=[s(`<p><img src="https://pbs.twimg.com/media/HF4PTCYasAM9kk5?format=jpg&amp;name=large" alt="图像"></p><p>这是这个系列第二篇文章，我会把自己最近从零开始梳理，整理 Mac 使用过程中的经验与步骤记录下来，作为留存与分享。如果拿到一款新的Mac，我最先安装的AI工具就是Codex App了，因为它无需其他依赖直接下载安装即可使用。</p><p>它不仅操作简单，安装方便，更易于操作使用。</p><p>我的Mac使用指南系列文章：</p><blockquote><p>4月10日</p></blockquote><p>本文主要的内容如下目录</p><ul><li>通过Homebrew安装Codex App</li><li>使用Codex App 安装GitHub Cli</li><li>准备克隆代码</li><li>修改仓库内容，并提交</li><li>最后，附新建仓库指引</li></ul><h2 id="_1、通过homebrew-安装codex-app" tabindex="-1">1、通过Homebrew 安装Codex App <a class="header-anchor" href="#_1、通过homebrew-安装codex-app" aria-label="Permalink to &quot;1、通过Homebrew 安装Codex App&quot;">​</a></h2><p>如果你还没有安装Homebrew可以看看我上面的系列文章的第一篇。</p><p>Codex App就是OpenAI 推出的AI Agent 桌面客户端，打开终端使用brew执行如下命令。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 先查找 codex-app有没有</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex-app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 查找完了 一般最好确认一下是不是openai的codex app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex-app</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">## 找到后安装</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex-app</span></span></code></pre></div><p>命令执行完毕之后，到App中查看Codex App 是否已经有了。安装成功如下图所示，点击打开即可。</p><p><img src="https://pbs.twimg.com/media/HFBxT07a8AAeja3?format=jpg&amp;name=large" alt="图像"></p><p>打开之后，点击继续使用ChatGPT登录，就会打开浏览器进行授权登录，登录完毕就可以跟AI进行对话了。</p><h2 id="_2、使用codex-app安装github-cli" tabindex="-1">2、使用Codex App安装GitHub CLI <a class="header-anchor" href="#_2、使用codex-app安装github-cli" aria-label="Permalink to &quot;2、使用Codex App安装GitHub CLI&quot;">​</a></h2><p><img src="https://pbs.twimg.com/media/HFB3zs8bgAAQTS3?format=jpg&amp;name=large" alt="图像"></p><p>看上面截图发现自己的仓库，在克隆代码的地方多了一个标签。所以直接点击Learn more, 把链接交给了Codex App。</p><blockquote><p>如果你没有建过Github仓库也没关系，我之前写过单独创建新仓库相关的文章，欢迎到文末查看。</p></blockquote><p><img src="https://pbs.twimg.com/media/HFB4q6qaAAAFiSO?format=jpg&amp;name=large" alt="图像"></p><p><strong>如果没有安装Homebrew,可以点击我上面的系列文章进行查看安装使用。</strong></p><p>安装Homebrew之后，继续根据上图来安装gh。</p><p><img src="https://pbs.twimg.com/media/HFB5SMSaEAEkrmz?format=jpg&amp;name=large" alt="图像"></p><p>就会开始后台执行gh auth login，然后打开浏览器进行授权登录，比之前的SSH还是方便了很多。</p><p><img src="https://pbs.twimg.com/media/HFB7jWObMAAfHPN?format=jpg&amp;name=large" alt="图像"></p><h2 id="_3、准备克隆代码" tabindex="-1">3、准备克隆代码 <a class="header-anchor" href="#_3、准备克隆代码" aria-label="Permalink to &quot;3、准备克隆代码&quot;">​</a></h2><p>首先需要找到一个本地路径，存放克隆仓库的代码。</p><p>然后从github上复制使用GitHub CLI标签下的命令行。</p><p><img src="https://pbs.twimg.com/media/HFB8FKObcAAfnPK?format=jpg&amp;name=large" alt="图像"></p><h2 id="_4、修改仓库内容-并提交" tabindex="-1">4、修改仓库内容，并提交 <a class="header-anchor" href="#_4、修改仓库内容-并提交" aria-label="Permalink to &quot;4、修改仓库内容，并提交&quot;">​</a></h2><p><img src="https://pbs.twimg.com/media/HFB8_abaYAErfgR?format=jpg&amp;name=large" alt="图像"></p><p>我随便将README.md中的内容，删减了一点，然后跟他说提交内容。</p><p><img src="https://pbs.twimg.com/media/HFB90E9akAAcsq0?format=jpg&amp;name=large" alt="图像"></p><p>到github看效果</p><p><img src="https://pbs.twimg.com/media/HFB-maBaMAAnAzu?format=jpg&amp;name=large" alt="图像"></p><h2 id="_5、最后" tabindex="-1">5、最后 <a class="header-anchor" href="#_5、最后" aria-label="Permalink to &quot;5、最后&quot;">​</a></h2><p>GitHub CLI 支持的功能还有非常多，可以结合本地的Agent 客户端体验很多功能。</p><p><img src="https://pbs.twimg.com/media/HFB_mVzaUAAlXZQ?format=jpg&amp;name=large" alt="图像"></p><p>当然了，上面我是直接把原来有的仓库文件进行克隆本地，你也可以直接创建一个新的仓库，然后与本地文件直接进行关联上传提交，思路其实是一样的。</p><blockquote><p>3月22日</p></blockquote><p>这篇文章中的“<strong>4、将代码上传github</strong>”，演示的就是新建仓库并上传项目文件的过程，可以参考并结合上面的功能命令进行实测，也是一个不错的尝试。</p>`,40)]))}const g=p(t,[["render",o]]);export{d as __pageData,g as default};
